import { customElement, html, property } from '@umbraco-cms/backoffice/external/lit';
import { FormsInputFormElement } from '@umbraco-forms/components';
import { FormsFormPickerBaseElement } from './form-picker-base.element';

const elementName = "forms-form-picker-multiple-property-editor";

@customElement(elementName)
export class FormsFormPickerMultiplePropertyPickerElement extends FormsFormPickerBaseElement {

  @property({ type: Array<String> })
  public value: Array<string> = [];

  constructor() {
    super();
    this.allowMultiple = true;
  }

  #onPickedFormsChange(event: Event) {
    const target = event.target as FormsInputFormElement;
    this.value = target.selection;
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  render() {
    return html`<forms-input-form
      .selection=${this.value}
      .multiple=${this.allowMultiple}
      .allowedFolders=${this.allowedFolders}
      .allowedForms=${this.allowedForms}
      @change=${this.#onPickedFormsChange}
      slot="editor"></forms-input-form>`;
  }
}

export default FormsFormPickerMultiplePropertyPickerElement;

declare global {
    interface HTMLElementTagNameMap {
        [elementName]: FormsFormPickerMultiplePropertyPickerElement;
    }
}
